import java.util.Arrays;

public int minimizeTheDifference(int[][] mat, int target) {
    int m = mat.length;
    int n = mat[0].length;

    int[][] dp = new int[m][800 * 70 + 1];
    dp[0] = Arrays.copyOf(mat[0], n);

    for (int i = 1; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int k = 800 * 70; k > 0; k--) {
                if (k - mat[i][j] >= 0 && dp[i - 1][k - mat[i][j]] != 0) {
                    dp[i][k] = 1;
                }
            }
        }
    }

    int min_diff = Integer.MAX_VALUE;
    for (int k = 0; k <= 800 * 70; k++) {
        if (dp[m - 1][k] != 0) {
            min_diff = Math.min(min_diff, Math.abs(k - target));
        }
    }

    return min_diff;
}
```


